INSERT INTO `articles` (`id`, `titre`, `description_courte`, `contenu`, `date_publication`, `id_categorie`, `id_auteur`, `image`, `est_supprime`) VALUES
(8, 'Transparence et gouvernance des ressources extractives : Le Sénégal noté “Très bien”', 'Transparence et gouvernance des ressources extractives : Le Sénégal noté “Très bien”', '“Très bon”. C’est le score qui a été décerné au Sénégal au bout de son troisième processus de validation, à l’aune de la mise en œuvre de la Norme ITIE 2023. Le pays a obtenu la note de 89 sur 10, qui conforte son leadership mondial dans le domaine. \r\n\r\n“Avec 89 sur 100, le Sénégal maintient son leadership à travers le monde et démontre que le niveau de transparence est très satisfaisant, que non seulement la norme ITIE est pertinente au Sénégal, mais qu\'il y a une bonne inclusivité dans la gestion des ressources naturelles”, a expliqué Taddée Adiouma Seck.\r\n\r\nLe Secrétaire Permanent du Comité national de l’Initiative pour la transparence dans les industries extractives (Itie-Sénégal) s’exprimait ce mardi, lors d’un point de presse sur la présentation des résultats du processus de validation. \r\n\r\nEn effet, pour la composante “résultat et impact de la mise en œuvre”, le Sénégal a été noté 92,5 sur 100. Pour les aspects liés à “l\'engagement des parties prenantes”, le pays a obtenu 87,5 sur 100. Quant aux aspects liés à la transparence, une note de 81 lui a été décernée.\r\n\r\n“Sur presque toutes les composantes, nous sommes vraiment à un niveau très élevé, ou à une performance très élevée. Les déterminants qui nous ont valu ce score, c\'est globalement le plan de travail. La manière dont le Sénégal réalise son plan de travail est très appréciée”, assure M. Seck\r\n\r\nMais, le Sénégal n’aura pas obtenu de bons scores partout. Il a été moins bien noté pour les transferts infranationaux. M. Seck souligne que “c\'est le grand défi de gouvernance du Sénégal, puisque les dispositifs juridiques mis en œuvre depuis plus d\'une décennie ne sont pas fonctionnels”. A ce niveau, le Sénégal a obtenu la note de 50 sur 100.\r\n\r\nEn effet, le pays a mis en place des outils de redistribution de la rente minière à travers le Fonds de péréquation et d\'appui et le Fonds d\'appui au développement local. Mais, ces outils peinent à être appliqués depuis plus d\'une décennie.\r\n\r\n“Pour le Fonds de péréquation, malgré les arrêtés de redistribution, les transferts ne sont pas effectifs dans la réalité. Il n\'y a eu qu\'un seul transfert en 2020”, regrette M. Seck.\r\n\r\nPrésident du comité national de l’ITIE Sénégal, Thialy Faye a salué une performance globalement remarquable. Celle-ci traduit, dit-il, l’ampleur des progrès réalisés par notre pays dans la gouvernance du secteur extractif. \r\n\r\nMais, il a tenu à souligner que “ce score de 89 sur 100 ne constitue pas une finalité, il représente plutôt une base solide sur laquelle nous devons continuer de bâtir”.', '2026-03-24 19:22:53', 9, 1, 'art_69c2e48dbf7d64.66170024.jpeg', 0),
(9, 'Cheikh Tidiane Dièye sur les révélations du Times : « Aucun emprunt n’a été caché »', 'Le sujet est sur toutes les lèvres. Selon une enquête publiée ce 23 mars par le quotidien britannique Financial Times, le Sénégal aurait secrètement contracté des emprunts s\'élevant à 650 millions d\'euros auprès d\'institutions internationales.', 'Le sujet est sur toutes les lèvres. Selon une enquête publiée ce 23 mars par le quotidien britannique Financial Times, le Sénégal aurait secrètement contracté des emprunts s\'élevant à 650 millions d\'euros auprès d\'institutions internationales. Une dette jugée « cachée » contractée dans des conditions « opaques » (sans informer le Parlement) via le mécanisme des Total Return Swaps avec l\'Africa Finance Corporation et First Abu Dhabi Bank, qui aurait servi à éviter un défaut de paiement imminent.\r\n\r\nPrenant la balle au bond, le ministre de l’hydraulique et de l’assainissement, Cheikh Tidiane Dièye pointe un article « tendancieux » et tire à boulets rouges sur les opposants qui veulent en faire un scandale.\r\n\r\n« Hier, certains annonçaient que le Sénégal ferait défaut et ne pourrait pas honorer ses engagements. Le Sénégal a payé. À temps. Et avec la manière », écrit-il dans un post sur le réseau social X.\r\n\r\n« Aujourd’hui, les mêmes s’accrochent à un article déséquilibré, confus et largement tendancieux du Financial Times pour reconnaître, certes, que le Sénégal a honoré ses engagements, mais en insinuant qu’il l’aurait fait grâce à des emprunts non déclarés au marché ou au FMI. Rien que ça », ajoute Cheikh Tidiane Dièye, louant « la résilience » et la « créativité hors norme » dont le gouvernement a fait preuve face à « une dette étouffante héritée du régime précédent ».\r\n\r\nCheikh Tidiane Dièye se veut clair sur le sujet : « aucun emprunt n’a été caché ». À l’en croire, « tout a été programmé dans la Stratégie de gestion de la dette à moyen termes (SDMT), inscrite dans les lois de finances et approuvée par l’Assemblée nationale ».\r\n\r\nD’après le ministre, les opérations de marché réalisées « figurent dans le plan de financement 2025 », même si le Times et certains acteurs politiques sénégalais dont des députés soutiennent le contraire. « Les instruments financiers utilisés, notamment les Total Return Swaps, ainsi que les mécanismes à travers lesquels ils opèrent, ont été portés à la connaissance des partenaires financiers du Sénégal, en particulier le Fonds monétaire international (FMI) », souligne-t-il, s’inscrivant en faux contre les allégations du Times.', '2026-03-24 19:31:43', 9, 4, 'art_69c2e69f1fd8d5.99374627.jpg', 0),
(10, 'Mosquée omarienne : le problème des bourses des étudiants s’invite dans le sermon de la korité', 'Mosquée omarienne : le problème des bourses des étudiants s’invite dans le sermon de la korité', 'Les violents affrontements entre étudiants et forces de l’ordre pour des bourses non payées, qui ont conduit à la mort du pensionnaire de la faculté de médecine Abdoulaye Bâ, se sont invités dans le sermon de korité de l’imam de la mosquée orienne. «Nous avons tous été étudiants et nous mesurons à sa juste valeur ce que la bourse représente pour un étudiant. Si la bourse n’est pas payée, ils ont des problèmes», concède Thierno Seydou Mountaga Tall, frère du khalife, Thierno Madani, dans des propos rapportés par L’Observateur.\r\n\r\nMais s’il affiche sa compassion face à la situation des boursiers des universités publiques, le religieux leur recommande d’opter pour des négociations apaisées en cas de frictions avec les autorités. «Les problèmes liés au paiement des bourses peuvent être réglés sans affrontement entre forces de l’ordre et étudiants. Il faut privilégier le dialogue : à chaque fois qu’il y a contestation, je conseille aux étudiants d’accepter de se mettre autour d’une table avec l’État», martèle Thierno Seydou Mountaga Tall.', '2026-03-24 19:34:47', 9, 4, 'art_69c2e757562524.72343320.jpeg', 0),
(11, 'Décision du jury d’appel de la CAF : Le Sénégal a officiellement saisi le TAS (média)', 'La Fédération sénégalaise de football (FSF) est passée à l’offensive. L’instance dirigeante du football sénégalais a officiellement saisi le Tribunal arbitral du sport (TAS) ce mardi afin de contester le retrait du titre de champion d’Afrique.', 'La Fédération sénégalaise de football (FSF) est passée à l’offensive. L’instance dirigeante du football sénégalais a officiellement saisi le Tribunal arbitral du sport (TAS) ce mardi afin de contester le retrait du titre de champion d’Afrique.\r\n\r\nAlors que le Sénégal s’était imposé sur le terrain face au Maroc (1-0) lors de la finale de la CAN, la FSF a déposé son recours auprès du TAS à la suite de la décision de la Confédération africaine de football (CAF) de destituer les Lions sur tapis vert (0-3), rapporte le site Foot mercato. Une issue controversée qui continue de susciter de vives réactions.\r\n\r\nLe Sénégal espère ainsi obtenir l’annulation de cette décision et faire valoir le résultat acquis sur le terrain.\r\n\r\nL’affaire est désormais entre les mains du TAS, appelé à trancher ce litige qui agite le monde du football.', '2026-03-24 19:38:19', 13, 4, 'art_69c2e82b99d607.75436622.webp', 0),
(12, 'Départ de son entraîneur Souleymane Diallo : Le Jaraaf opté pour le duo Ciré Dia-Demba Ba pour assurer l’intérim', 'Le Jaraaf de Dakar tourne une nouvelle page.', 'Le Jaraaf de Dakar tourne une nouvelle page. À la suite de la nomination de son entraîneur Souleymane Diallo au poste de directeur technique national du football sénégalais, le club de la Médina a rapidement désigné une solution en interne pour assurer la continuité. Les dirigeants ont opté pour un duo bien connu de la maison : l’ancien buteur Ciré Dia et Demba Ba. Les deux techniciens auront pour mission de conduire l’équipe en intérim, dans un contexte sportif délicat.\r\n\r\nActuel 9e de Ligue 1, le Jaraaf traverse une saison compliquée, marquée notamment par une absence de victoire depuis le début de l’année 2026. Un défi de taille attend donc le tandem appelé à redresser la dynamique du club le plus titré du Sénégal.\r\n\r\nMalgré ces résultats en demi-teinte, le Jaraaf a tenu à rendre un hommage appuyé à Souleymane Diallo pour le travail accompli durant son passage sur le banc du club de la Médina. Dans un communiqué, le club a salué une nomination méritée.\r\n\r\n« Le club adresse ses plus chaleureuses félicitations à son entraîneur, Souleymane Diallo, pour sa nomination au poste de directeur technique national. Une reconnaissance du travail, de l’engagement et de la compétence d’un homme qui a toujours œuvré pour le développement du football. Nous lui souhaitons plein succès dans cette nouvelle mission au service du football national ».\r\n\r\nUne nouvelle ère s’ouvre donc pour le Jaraaf, avec l’espoir de relancer la machine sous la houlette de ce duo intérimaire.', '2026-03-24 19:41:32', 13, 3, 'art_69c2e8ece81e83.11169873.jpg', 0),
(13, 'Finale Sénégal - Maroc : L\'argument totalement lunaire brandi par un juriste sur la presse marocaine', 'Finale Sénégal - Maroc : L\'argument totalement lunaire brandi par un juriste sur la presse marocaine', 'Sur la presse marocaine, c\'est la réjouissance, après la décision de la Confédération africaine de football de leur accorder le titre de la CAN 2025 sur tapis vert, aux dépens du Sénégal. Sur Medias24, l\'un des principaux sites d\'informations marocains, Reda Belhoucine, président du Tribunal de première instance de Ouezzane (Nord-ouest), a tenté de justifier cette décision controversée de l\'instance dirigeante du foot africain.\r\n\r\nDans un texte, le juriste a mis en avant un argument totalement lunaire pour expliquer la défaite des Marocains face aux Sénégalais le 18 janvier dernier. Selon Belhoucine, les Lions de la Téranga ont exercé une pression psychologique énorme sur l\'arbitre Jean-Jacques Ndala telle que le but de la victoire, inscrit par Pape Guèye, aurait dû être refusé... pour une faute dit-il de Chérif Ndiaye sur le défenseur marocain Jawad El Yamiq.\r\n\r\n\"Cet abandon temporaire a placé le corps arbitral dans une posture d\'une extrême vulnérabilité psychologique, altérant l\'environnement de l\'arbitre qui, tiraillé par la menace implicite d\'un arrêt définitif de la finale, a vu sa priorité glisser de l\'application stricte des lois du jeu vers la sauvegarde absolue de l\'événement. Cette forme d\'intimidation environnementale a trouvé son illustration la plus probante lors de la validation du but sénégalais, séquence durant laquelle l\'arbitre, manifestement tétanisé par l\'appréhension d\'un nouvel incident, a omis de sanctionner une faute d\'attaque flagrante commise par le joueur sénégalais numéro 12, lequel a délibérément bousculé un défenseur marocain pour s\'ouvrir la trajectoire de tir\", écrit Belhoucine sur Medias24.\r\n\r\nLe président du tribunal de première instance de Ouezzane d\'ajouter : \"En tirant ainsi un profit direct et décisif de sa propre irrégularité, l\'attaquant a violé non seulement la Loi 12 de l\'IFAB - qui invalide formellement toute action où un joueur bouscule son adversaire pour le déséquilibrer ou dégager l\'axe du but -mais également le principe universel selon lequel nul ne peut se prévaloir de sa propre turpitude, démontrant de facto que le mutisme du sifflet arbitral découlait d\'une liberté d\'appréciation anéantie par la contrainte psychologique du retrait soi-disant temporaire\". Incroyable !', '2026-03-24 19:43:38', 13, 3, 'art_69c2e96a3b1207.83044584.jpg', 0),
(14, 'Médina Yoro Foulah : 330 litres d\'essence saisis par la gendarmerie, le propriétaire prend la fuite', 'Médina Yoro Foulah : 330 litres d\'essence saisis par la gendarmerie, le propriétaire prend la fuite', 'Dans le cadre de sa mission de sécurisation, la Brigade de Proximité de Médina Yoro Foulah a procédé à une importante saisie de carburant dans la nuit du 20 mars 2026.\r\nVers 23 heures, les gendarmes ont intercepté onze bidons de 30 litres d\'essence chacun, soit un total de 330 litres, au village de Méo-Ndiobène, commune de Niaming.\r\n\r\nSelon le colonel Ibrahima Ndiaye, le propriétaire a pris la fuite avant l\'arrivée des forces de l\'ordre. Les recherches se poursuivent pour l\'identifier et l\'interpeller.\r\n\r\nLa Gendarmerie nationale rappelle que son centre d\'appel est accessible gratuitement aux numéros verts 123 et 800 00 20 20 pour tout renseignement utile.', '2026-03-24 19:46:13', 11, 3, 'art_69c2ea05474448.65891909.jpg', 0),
(15, '\"Il ne sort jamais de sa cellule\" : Les confidences d\'un ex-codétenu sur Pape Cheikh Diallo !', 'Un ancien détenu de la Maison d’arrêt de Rebeuss a brisé le silence pour livrer des détails inédits sur le quotidien carcéral de l\'animateur Pape Cheikh Diallo, actuellement sous les verrous.', 'Un ancien détenu de la Maison d’arrêt de Rebeuss a brisé le silence pour livrer des détails inédits sur le quotidien carcéral de l\'animateur Pape Cheikh Diallo, actuellement sous les verrous.\r\n\r\nL’ex-pensionnaire de Rebeuss, prénommé Latyr, a tenu à démentir formellement les rumeurs persistantes concernant une prétendue « nouvelle vie » de l\'animateur, lequel aurait dirigé des prières durant le mois de Ramadan.\r\n\r\n« Comment pouvez-vous croire que des musulmans acceptent d’être guidés par un homosexuel ? Pape Cheikh Diallo ne dirigera jamais une prière en prison », a-t-il tranché avec fermeté.\r\n\r\nUn quotidien marqué par l\'isolement\r\n\r\nSelon ce témoin oculaire, l\'homme de média vivrait dans un isolement quasi total pour éviter les regards et les confrontations. « D’ailleurs, l’homme de médias n’ose même pas sortir dans la cour pour profiter des promenades. Par pudeur, il reste tout le temps dans sa chambre. Ses seules sorties se font pour aller à l’infirmerie », rapporte Latyr.\r\n\r\nUn appel surprenant à l\'administration pénitentiaire\r\n\r\nPlus troublant encore, l\'ancien détenu a interpellé l\'administration pénitentiaire sur un besoin spécifique lié, selon ses dires, à la condition physique de certains détenus. Latyr a invité les autorités à se ravitailler en couches pour adultes pour pallier des problèmes d\'incontinence chez les homosexuels incarcérés, affirmant de manière directe que « ces derniers en ont réellement besoin ».', '2026-03-24 19:51:07', 11, 5, 'art_69c2eb2b7cb948.49565605.jpg', 0),
(16, 'Clash : Ngaaka Blindé relance la guerre contre Dip et Akhlou Brick, la toile s\'enflamme', 'Clash : Ngaaka Blindé relance la guerre contre Dip et Akhlou Brick, la toile s\'enflamme', 'Dans son nouveau freestyle, Ngaaka Blindé, le rappeur originaire de Guédiawaye, n’a pas mâché ses mots. Avec la punchline percutante « Mbour ak Grand-Yoff samay petit lagn », il s’attaque directement à ses rivaux, affirmant sans détour sa supériorité artistique. Une manière de se positionner comme le \"boss\" face à Dip Doundou Guiss (originaire de Grand-Yoff) et Akhlou Brick Paradise (basé à Mbour).\r\n\r\nLa réaction de Dip Doundou Guiss ne s’est pas fait attendre. Par un commentaire acerbe — « Boudé genrou couplet yi, ragal na 100 mil sakh douñ niou ko fey » —, il répond sèchement en remettant en cause la valeur marchande et lyrique des textes de Ngaaka Blindé. Une réplique piquante qui prouve que les tensions entre les deux ténors sont loin d\'être apaisées.', '2026-03-24 22:28:52', 17, 5, 'art_69c310243e5c70.77607395.jpg', 0),
(17, 'Carnet rose ou buzz ? Mia Guissé affole la toile avec un mystérieux « Madame S »', 'La chanteuse Mia Guissé a semé le doute et enflammé la toile après une publication intrigante partagée sur sa page Facebook.', 'La chanteuse Mia Guissé a semé le doute et enflammé la toile après une publication intrigante partagée sur sa page Facebook.\r\n\r\nDans un post bref mais lourd de sens, l’artiste a écrit : « Mrs S… Mbeguel day yokou tarr, dagay glow sa kanam am léer. » Cette déclaration était accompagnée d’émojis \"cœur\" et \"bague\", généralement associés à un mariage ou à des fiançailles.\r\n\r\nL’expression « Mrs S », littéralement « Madame S », a particulièrement attiré l’attention des internautes, laissant penser que la chanteuse aurait officiellement changé de statut matrimonial. Quant à la phrase en wolof, elle évoque un amour si fort qu’il illumine le visage, renforçant l’idée d’un heureux événement.\r\n\r\nTrès rapidement, les réactions se sont multipliées sous la publication. Entre messages de félicitations, prières et vœux de bonheur, de nombreux fans et internautes semblent avoir interprété ce message comme l’annonce d\'une union officielle. Cependant, à l’heure actuelle, aucune déclaration supplémentaire n’est venue confirmer clairement l’information, ni révéler l’identité de l’éventuel époux.\r\n\r\nAnnonce personnelle ou coup de communication ?\r\n\r\nConnue pour son sens aigu de la communication et sa proximité avec son public, Mia Guissé pourrait aussi réserver une surprise d\'une autre nature : nouveau projet musical, clip imminent ou concept artistique autour de l’amour ? L’artiste n’en est d\'ailleurs pas à son premier message énigmatique.\r\nEn attendant une confirmation formelle, une chose est sûre : la publication a réussi son pari en captivant l’attention et en faisant vibrer la blogosphère sénégalaise.', '2026-03-24 22:32:07', 17, 5, 'art_69c310e7e706d8.27775330.png', 0),
(18, 'Sénégal : Le Ministère de la Santé lance une campagne de recrutement, Voici les détails (Photo)', 'Le ministère de la Santé et de l’Hygiène publique a lancé un appel à candidatures dans le cadre du renforcement du Système national d’information sanitaire ...', 'Accueil • Arts de Vivre • Santé •\r\n\r\nSénégal : Le Ministère de la Santé lance une campagne de recrutement, Voici les détails (Photo)\r\nPublié le 24/12/2025 à 20:22 - Mis à jour le 24/12/2025 à 20:22\r\n Lire dans l\'application\r\nPartager\r\n91\r\n\r\n Copier le lien\r\nywAAAAAAQABAAACAUwAOw== - Senenews - Actualité au Sénégal, Politique, Économie, Sport\r\nPar \r\nBarry Souleymane\r\n \r\nSuivre\r\nLe ministère de la Santé et de l’Hygiène publique a lancé un appel à candidatures dans le cadre du renforcement du Système national d’information sanitaire (SNIS). Cette initiative vise le recrutement d’agents contractuels pour appuyer la gestion et l’exploitation des données sanitaires à l’échelle nationale.\r\n\r\nVoir plus\r\nla Santé\r\nSanté\r\nsanté\r\nSelon le document officiel, les profils recherchés doivent être titulaires d’un diplôme de niveau Licence ou Master dans les domaines de la santé publique, de la santé communautaire, des statistiques, de l’informatique ou du data management. Les candidats doivent être de nationalité sénégalaise et justifier d’au moins une année d’expérience en gestion de données sanitaires ou dans un service de santé.\r\n\r\nLa maîtrise pratique du logiciel DHIS2 constitue un atout majeur, tout comme une bonne connaissance des outils informatiques tels que Excel, PowerPoint, R ou leurs équivalents. Les postulants devront également avoir une bonne connaissance du système national d’information sanitaire et des outils de rapportage.\r\n\r\nEnfin, le ministère insiste sur des qualités personnelles essentielles, notamment le sens de l’éthique, la rigueur professionnelle et la discrétion.', '2026-03-24 23:38:08', 15, 7, 'art_69c32060286426.72423242.jpg', 0),
(19, 'Sénégal : Le Ministère de la Santé lance une campagne de recrutement, Voici les détails (Photo)', 'Le ministère de la Santé et de l’Hygiène publique a lancé un appel à candidatures dans le cadre du renforcement du Système national d’information sanitaire ...', 'Selon le document officiel, les profils recherchés doivent être titulaires d’un diplôme de niveau Licence ou Master dans les domaines de la santé publique, de la santé communautaire, des statistiques, de l’informatique ou du data management. Les candidats doivent être de nationalité sénégalaise et justifier d’au moins une année d’expérience en gestion de données sanitaires ou dans un service de santé.\r\n\r\nLa maîtrise pratique du logiciel DHIS2 constitue un atout majeur, tout comme une bonne connaissance des outils informatiques tels que Excel, PowerPoint, R ou leurs équivalents. Les postulants devront également avoir une bonne connaissance du système national d’information sanitaire et des outils de rapportage.\r\n\r\nEnfin, le ministère insiste sur des qualités personnelles essentielles, notamment le sens de l’éthique, la rigueur professionnelle et la discrétion.', '2026-03-24 23:39:05', 15, 7, NULL, 0),
(20, 'Affaire SOFTCARE : le ministère de la Santé prend une décision ferme, voici le Communiqué', 'Dakar, le 18 décembre 2025 – L’Agence de Régulation Pharmaceutique (ARP) a récemment mené une inspection au sein de l’entreprise SOFTCARE SN COMPANY LIMITED, provoquant ...', 'Dakar, le 18 décembre 2025 – L’Agence de Régulation Pharmaceutique (ARP) a récemment mené une inspection au sein de l’entreprise SOFTCARE SN COMPANY LIMITED, provoquant une vive polémique et de nombreuses interrogations dans l’espace public.\r\n\r\nEn réponse, le Ministère de la Santé et de l’Hygiène publique (MSHP), en sa qualité d’autorité de tutelle, a annoncé qu’une mission conjointe serait diligentée sans délai. Cette opération se fera en collaboration avec le Ministère du Commerce et de l’Industrie, afin de clarifier la situation et de faire toute la lumière sur cette affaire.\r\n\r\nLe MSHP a également rassuré le public, indiquant qu’il communiquerait prochainement des informations précises, vérifiées et conformes à la réalité, dans un souci de transparence et de responsabilité.\r\n\r\nPar ailleurs, le Ministère souligne qu’il prendra toutes les mesures correctives nécessaires, conformément à la législation en vigueur, tout en veillant à respecter les principes de justice et d’équité.\r\nEnfin, le Ministère a réaffirmé son engagement à préserver la santé publique, à garantir la sécurité sanitaire et à assurer une régulation rigoureuse du secteur pharmaceutique, pour le bénéfice de l’ensemble des populations.', '2026-03-24 23:43:08', 15, 7, 'art_69c3218c779c02.97906007.jpeg', 0),
(21, 'Sénégal: le DAF, un département du ministère de l\'Intérieur, touché par une cyberattaque', 'Après le site des impôts en octobre dernier, cette fois c’est le département de l’automatisation des fichiers (DAF) qui a été touché par une cyberattaque. Cet organisme particulièrement sensible, rattaché au ministère de l’Intérieur permet, entre autres, de délivrer les cartes nationales d’identité.', 'L\'étendue des données piratées est pour l\'heure inconnue mais les spécialistes en cybersécurité sont formels : l\'attaque informatique sur le département de l\'automatisation des fichiers (DAF) est particulièrement grave.\r\n\r\nElle l\'est notamment car ce service rattaché au ministère de l\'Intérieur dirige et sécurise toutes les données biométriques des citoyens sénégalais : les cartes nationales d\'identité, le fichier électoral et la modernisation de l\'état civil. Des données donc particulièrement sensibles. Un groupe tout récemment apparu au début de l\'année et quasi inconnu a revendiqué la cyberattaque. Il a publié sur le darkweb quelques-unes des données piratées.\r\n\r\nSi l\'attaque criminelle ne fait donc pas de doute, ce qui a été rendu public ne permet pas de connaître l\'étendue des dégâts. Le groupe criminel affirme avoir aspiré 139 téraoctets, soit une quantité vertigineuse, de données. Une information impossible à vérifier pour l\'heure sans une investigation numérique musclée.\r\nL\'Afrique, de plus en plus connectée, est un terrain de jeu idéal pour les cybercriminels\r\nAprès une attaque en octobre 2025 sur le site internet des impôts du Sénégal, cette nouvelle intrusion rappelle l\'urgence de prendre des mesures. Sur le continent, une dizaine de pays sont par exemple munis d\'une agence nationale de la cybersécurité.\r\n\r\nSelon Clément Domingo, spécialiste en cybersécurité, « le Sénégal n\'est pas particulièrement vulnérable », mais « la numérisation grandissante » de l\'Afrique entraîne des hausses des attaques informatiques. « Il y a une énorme méconnaissance de nos dirigeants et de la population : on pense qu\'il n\'y a pas de cyberattaques en Afrique. Personne n\'en parle. C\'est un biais où on se dit qu\'il ne se passe rien sur le continent africain. C\'est totalement faux, c\'est même le contraire aujourd\'hui », explique-t-il.\r\n\r\n« L\'Afrique est devenue, depuis quelques mois, le \'\'bac à sable\'\' des cybercriminels. C\'est là où ils testent leurs nouvelles armes. Des États, des entreprises et donc des cybercriminels ont compris que ce taux grandissant de numérisation de l\'Afrique en fait un continent de plus en plus exposé. Et le Sénégal n\'en réchappe pas », insiste Clément Domingo.', '2026-03-24 23:53:09', 18, 6, 'art_69c323e5daa7b5.42070096.jpg', 0),
(22, 'Une attaque ransomware au cœur de la Dgid, après le vol des ordinateurs au niveau du Trésor', 'Une cyberattaque sans précédent', 'Le Sénégal traverse une crise numérique majeure. La Direction générale des Impôts et domaines (Dgid), institution centrale dans la gestion fiscale du pays, est frappée de plein fouet par une attaque informatique d’une ampleur inédite. Depuis plus d’une semaine, ses logiciels de gestion fiscale et de recouvrement sont totalement paralysés.\r\nLes pirates à l’origine de l’opération, se présentant sous le nom de Black Shrantac, affirment avoir volé 1 Téraoctet (To) de données sensibles et exigent le paiement d’une rançon astronomique de 10 millions d’euros, soit environ 6, 5 milliards de francs Cfa, pour libérer les systèmes et restituer les informations.\r\nCet épisode survient après le vol d’ordinateurs au niveau du Trésor public il y a quelques mois. Deux événements rapprochés qui posent une question inquiétante : sommes-nous face à une offensive coordonnée contre les finances publiques sénégalaises ?\r\nLa cybersécurité : une obligation nationale\r\nIl est urgent de reconnaître que la cybersécurité doit devenir une priorité absolue pour l’Etat et ses agents. Trop souvent perçue comme une contrainte technique réservée aux informaticiens, elle doit être considérée comme une obligation pour tous les fonctionnaires manipulant des données sensibles.\r\nLa réalité est simple : la faille humaine est aujourd’hui la première porte d’entrée des cybercriminels. Un mot de passe trop faible, un clic sur un lien piégé, une connexion à un site non sécurisé… il suffit d’une erreur pour exposer tout un réseau. Dans une administration comme la Dgid, cela revient à mettre en péril les finances de l’Etat et la confiance des citoyens.\r\nQu’est-ce qu’un ransomware ?\r\nPour comprendre la situation, il faut d’abord expliquer ce qu’est un ransomware. Il s’agit d’un logiciel malveillant conçu pour chiffrer les données d’un système informatique et les rendre inaccessibles. Les cybercriminels exigent ensuite le paiement d’une rançon, généralement en cryptomonnaie, en échange de la clé de déchiffrement.\r\nMais les attaques modernes ne s’arrêtent plus là. Les pirates copient aussi les données avant de les verrouiller, puis menacent de les divulguer publiquement en cas de refus de paiement. C’est exactement ce qui est en train de se produire à la Dgid : les pirates affirment détenir 1 To de fichiers fiscaux et administratifs, et menacent de les publier si leurs conditions ne sont pas remplies.\r\nLe groupe Black Shrantac : un acteur du cybercrime organisé\r\nLe groupe Black Shrantac n’est pas un novice. Comme d’autres collectifs spécialisés dans le chantage numérique, il cible en priorité les institutions financières et administratives, là où la pression est maximale et où l’impact d’une paralysie est immédiat.\r\nSelon les premiers éléments, ce groupe serait basé en Europe, ce qui complique l’enquête, et nécessitera une coopération internationale. Leur mode opératoire est classique, mais redoutable :\r\n1. Infiltration d’un réseau via un phishing, une faille ou une connexion non sécurisée.\r\n2. Exfiltration des données sensibles.\r\n3. Chiffrement massif des serveurs pour bloquer toute activité.\r\n4. Publication de preuves de vol sur leurs canaux de communication pour mettre la victime sous pression.\r\n5. Négociation d’une rançon, assortie de menaces de divulgation.\r\nLes conséquences pour le Sénégal\r\nL’attaque contre la Dgid a des répercussions multiples :\r\n• Economiques : la paralysie du recouvrement fiscal retarde la rentrée de recettes essentielles pour l’Etat, avec un impact direct sur le budget public.\r\n• Administratives : les contribuables, particuliers comme entreprises, se retrouvent bloqués dans leurs démarches.\r\n• Sociales : la confiance des citoyens dans la capacité de l’Etat à protéger leurs données est sérieusement ébranlée.\r\n• Sécuritaires : la publication éventuelle des données pourrait exposer les Sénégalais à des fraudes, des usurpations d’identité et des escroqueries ciblées.\r\nLa vigilance des fonctionnaires en première ligne\r\nLa cybersécurité ne dépend pas uniquement des outils et des firewalls. Elle repose aussi -et surtout- sur la discipline des utilisateurs. Dans ce contexte, il est indispensable de rappeler quelques règles simples que chaque agent de la Fonction publique doit appliquer :\r\n• Ne jamais utiliser son ordinateur professionnel pour se connecter aux réseaux sociaux.\r\n• Ne pas cliquer sur des liens ou pièces jointes suspects.\r\n• N’installer aucun logiciel non autorisé par l’administration.\r\n• Respecter les consignes des administrateurs système.\r\nDe leur côté, les responsables informatiques doivent :\r\n• Bloquer l’accès aux sites non professionnels.\r\n• Mettre régulièrement à jour les systèmes de sécurité.\r\n• Utiliser des solutions avancées de détection d’intrusion, capables d’identifier les attaques même quand elles sont camouflées par des faux négatifs.\r\nUne menace qui ne peut plus être ignorée\r\nTrop de Sénégalais pensent encore que la cybersécurité est un problème lointain, réservé aux grandes puissances. Or, la réalité s’impose :\r\n• Hier, le Trésor public a été touché.\r\n• Aujourd’hui, c’est la Dgid.\r\nSi ces attaques sont liées, les criminels pourraient viser d’autres institutions et provoquer un véritable black-out numérique. Avec la montée en puissance de l’Intelligence artificielle, les cyberattaques deviennent de plus en plus sophistiquées et destructrices. Comme l’ont montré les conflits récents dans le monde, les guerres modernes se mènent aussi dans le cyberespace.\r\nNe pas céder au chantage et nettoyer en profondeur\r\nFace à cette situation, certains pourraient être tentés de payer la rançon pour rétablir rapidement les services. Mais il faut être clair : payer ne garantit rien. Même après avoir reçu l’argent, les pirates peuvent :\r\n• Revendre les données sensibles à d’autres criminels.\r\n• Publier une partie des fichiers pour faire pression à nouveau.\r\n• Ou pire : garder un accès secret dans le système, grâce à une porte dérobée (backdoor), pour revenir plus tard et relancer une nouvelle attaque.\r\nC’est pourquoi la seule stratégie viable est de refuser le paiement, de nettoyer en profondeur les systèmes infectés et de renforcer durablement la sécurité numérique de toutes les administrations. Cela implique :\r\n• Des audits complets de cybersécurité.\r\n• La modernisation des infrastructures informatiques.\r\n• La formation continue des agents publics.\r\n• Une coopération étroite avec les partenaires internationaux.\r\nConclusion : un signal d’alarme pour tout le pays\r\nL’attaque contre la Dgid doit être vue comme un signal d’alarme. Elle montre que le Sénégal est désormais dans la ligne de mire des cybercriminels, et que ses institutions doivent se préparer à un environnement numérique hostile.\r\nIl ne s’agit pas seulement d’un problème technique, mais d’un enjeu de souveraineté nationale. Si l’Etat ne prend pas des mesures radicales dès maintenant, les prochaines attaques pourraient viser d’autres secteurs stratégiques : l’énergie, les télécommunications, ou même la santé.', '2026-03-24 23:58:00', 18, 6, 'art_69c32508dc0341.58077175.jpg', 0),
(23, 'Le ngalakh, un repas de Pâques', 'Comme pour toutes les religions, le partage est un principe cher au christianisme. Il se matérialise à travers l’aumône et l’entraide, surtout durant les célébrations cultuelles. C’est dans ce sens qu’il faut comprendre le repas distribué aux non-chrétiens à l’occasion des fêtes de Pâques : le ngalakh.', 'Au Sénégal, le ngalakh de Pâque symbolise le vivre ensemble entre chrétiens et musulmans. Pour sa fameuse recette, la famille Cabo habitant le quartier Quinzambougou de la commune de Tambacounda s’est réveillée. Sous nos yeux, Rose, l’aînée de cette famille de huit enfants se pointe au robinet pour chercher de l’eau en vue d’entamer le mélange. Pour préparer le ngalakh, il faut du sucre, du mil, de la pâte d’arachide, du pain de singe, du sucre, de l’arome, de l’ananas, de la noix de coco, du raisin.\r\n\r\nDans la cour, de grands récipients contenant du pain de singe et de la pâte d’arachide. Autour de ces bols, Rose et sa voisine commencent le mélange en attendant que les quelques femmes du quartier arrivent pour leur donner un coup de main.\r\nDurant plus d’une heure, elles trempent le pain de singe dans chacun des récipients qui contient déjà de l’eau et de la pâte d’arachide. Au final on obtient un liquide très consistant auquel la pâte d’arachide donne une couleur marron. Parallèlement, du couscous à base de mil est préparé qu’il s’agira ensuite d’ajouter dans ce liquide pour avoir enfin du ngalakh. Quant aux arômes, aux tranches d’ananas, au sucre, au coco râpé, au raisin, c’est pour donner un goût succulent au ngalakh qui est mis au frais pour éviter qu’il ne fermente.\r\n\r\nSi certaines familles chrétiennes choisissent le vendredi saint, dernier vendredi du mois de carême, d’autres par contre attendent le lendemain pour préparer ce repas qui est très prisé par les musulmans. Antoinette Cabo explique que si les musulmans aiment le ngalakh, c’est bien parce qu’il a la bénédiction de Dieu. Mais pour beaucoup de prêtres, ce repas n’a pas une histoire particulière de la religion chrétienne.\r\n\r\nÀ la fin de la préparation, des pots, des bouteilles, de petits seaux se bousculent prêts à être remplis et distribués aux voisins et aux proches, qu’ils soient chrétiens ou non. Le ngalakh, en plus de symboliser le partage, renforce la cohésion sociale entre les différentes confessions religieuses au Sénégal.', '2026-03-25 00:03:07', 16, 7, 'art_69c3263b8dafb8.90974718.png', 0),
(24, 'Le café Touba, café « saf »', 'Le café Touba est une boisson à base de café aromatisé au poivre de Guinée (le fruit de la Xylopia aethiopica) communément appelé poivre noir ou diar en wolof.', 'Il tire son nom de la ville sénégalaise de Touba et son origine est liée à la fraternité des Mourides ; on raconte que son fondateur, Cheikh Amadou Bamba, a ramené la recette du Gabon où il avait été envoyé en exil. Aujourd’hui encore, la fraternité mouride associe à cette boisson une grande valeur symbolique et la consomme à l’occasion de cérémonies religieuses.\r\n\r\nDepuis quelques années, le café Touba se popularise et, au delà des célébrations religieuses. Il est très facile de trouver des vendeurs ambulants, avec leur petit fourneau et leur casserole, qui le proposent dans la rue. Et on le trouve désormais en vente en sachets dans les boutiques de quartier.\r\n\r\nSon seul défaut : être vendu dans des petites tasses en plastique que les consommateurs jettent négligemment sur le trottoir...', '2026-03-25 00:04:46', 16, 7, 'art_69c3269ec223d2.90583578.jpg', 0);

